Multi-peak refinement (airmine refine_peaks)


Show code
refined &lt;- function(tag) {
  r &lt;- fread(file.path(RQ, sprintf("%s_peaks_refined_%s.csv", PFX, tag)))
  if (nrow(r) == 0) {
    return(r)
  }
  r[order(chr, -lod), .(
    chr,
    `pos (cM)` = round(pos, 1), `pos (Mb)` = round(bp_of(marker) / 1e6, 1),
    LOD = round(lod, 2), `perm 5% thr` = round(thresh, 2), marker,
    `1.5-LOD CI (Mb)` = ci_str(ci_left, ci_right),
    `candidate in CI` = mapply(cand_in_ci, chr, ci_left, ci_right)
  )]
}
rt &lt;- refined("taxon")
if (nrow(rt) == 0) cat("No refined peaks.") else knitr::kable(rt, caption = sprintf("Refined multi-peak QTL, taxon model (%d QTL across %d chromosomes).", nrow(rt), uniqueN(rt$chr)))


No refined peaks.

The scan

scan1 &lt;- function(i) {
  g &lt;- dos[i, ] # dosage across lines, NA where untyped
  ok &lt;- !is.na(g) & !is.na(y)
  n &lt;- sum(ok)
  if (n &lt; 20) {
    return(c(NA_real_, n))
  }
  gg &lt;- as.numeric(g[ok])
  if (stats::sd(gg) == 0) {
    return(c(NA_real_, n))
  }
  yy &lt;- y[ok]
  ff &lt;- droplevels(fam[ok])
  Xr &lt;- if (nlevels(ff) &gt; 1) model.matrix(~ff) else matrix(1, n, 1)
  RSS0 &lt;- sum(lm.fit(Xr, yy)$residuals^2)
  fit &lt;- lm.fit(cbind(Xr, gg), yy)
  RSS1 &lt;- sum(fit$residuals^2)
  df2 &lt;- n - fit$rank
  if (df2 &lt;= 0 || RSS1 &lt;= 0) {
    return(c(NA_real_, n))
  }
  c(pf(((RSS0 - RSS1) / 1) / (RSS1 / df2), 1, df2, lower.tail = FALSE), n)
}
out &lt;- mclapply(mk_idx, scan1, mc.cores = THREADS)
P &lt;- vapply(out, `[`, numeric(1), 1)
N &lt;- vapply(out, `[`, numeric(1), 2)

scan &lt;- data.table(
  SNP = mk, CHR = as.integer(chr_by[mk]),
  BP = as.integer(pos_by[mk]), P = P,
  n = as.integer(N)
)[order(CHR, BP)]
fwrite(scan, here("data/teonam/stam_gwas_scan_118k.csv")) # canonical output

